import * as fs from "fs";
import * as path from "path";

const WORKFLOW_CONTENT = `# Auto-generated by codd implement --sprint 59
# PromptNotes macOS .dmg バンドルビルドワークフロー
# 対象: macOS (darwin) のみ。Linux は別ジョブで扱う。

name: Build macOS DMG

on:
  push:
    tags:
      - 'v*.*.*'
  workflow_dispatch:

permissions:
  contents: write

jobs:
  build-macos:
    name: Build .dmg (macOS)
    runs-on: macos-latest
    env:
      TAURI_PRIVATE_KEY: \${{ secrets.TAURI_PRIVATE_KEY }}
      TAURI_KEY_PASSWORD: \${{ secrets.TAURI_KEY_PASSWORD }}
      APPLE_SIGNING_IDENTITY: \${{ secrets.APPLE_SIGNING_IDENTITY }}
      APPLE_ID: \${{ secrets.APPLE_ID }}
      APPLE_PASSWORD: \${{ secrets.APPLE_PASSWORD }}

    steps:
      - name: Checkout
        uses: actions/checkout@v4

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: '20'
          cache: 'npm'

      - name: Install Node dependencies
        run: npm ci

      - name: Setup Rust toolchain
        uses: dtolnay/rust-toolchain@stable
        with:
          targets: aarch64-apple-darwin,x86_64-apple-darwin

      - name: Cache Cargo registry
        uses: Swatinem/rust-cache@v2
        with:
          workspaces: './src-tauri -> target'

      - name: Install Tauri CLI
        run: cargo install tauri-cli --version "^2.0" --locked

      - name: Build frontend
        run: npm run build
        env:
          NODE_ENV: production

      - name: Build Tauri universal binary + DMG
        run: cargo tauri build --target universal-apple-darwin
        working-directory: .

      - name: Locate DMG artifact
        id: locate
        run: |
          DMG=$(find src-tauri/target/universal-apple-darwin/release/bundle/dmg -name "*.dmg" | head -1)
          echo "dmg_path=\${DMG}" >> "\$GITHUB_OUTPUT"
          echo "dmg_name=\$(basename \${DMG})" >> "\$GITHUB_OUTPUT"

      - name: Verify DMG integrity
        run: hdiutil verify "\${{ steps.locate.outputs.dmg_path }}"

      - name: Upload DMG artifact
        uses: actions/upload-artifact@v4
        with:
          name: promptnotes-macos-dmg
          path: \${{ steps.locate.outputs.dmg_path }}
          retention-days: 30

      - name: Attach DMG to GitHub Release
        if: startsWith(github.ref, 'refs/tags/')
        uses: softprops/action-gh-release@v2
        with:
          files: \${{ steps.locate.outputs.dmg_path }}
`;

export function generateCiWorkflow(
  outputPath: string = path.resolve(
    __dirname,
    "../../../../../.github/workflows/build-macos.yml"
  )
): void {
  const dir = path.dirname(outputPath);
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(outputPath, WORKFLOW_CONTENT, "utf8");
  console.log(`[generateCiWorkflow] ワークフローを生成しました: ${outputPath}`);
}

// CLI エントリポイント
if (require.main === module) {
  const outPath = process.argv[2];
  generateCiWorkflow(outPath);
}
